tool.command:
exec 3>&1 4>&2; exec > enzywizard.log 2>&1;
#set $input_name = $input_path.element_identifier ln -s '$input_path' '$input_name' && mkdir -p substrate_dir_raw substrate_dir && unzip -q '$substrate_zip' -d substrate_dir_raw &&
enzywizard-dock -i '$input_name' -s '$substrate_names' -d substrate_dir -o ./ --max_docking_attempt_num '$advanced.max_docking_attempt_num' $advanced.no_early_stop --exhaustiveness '$advanced.exhaustiveness' --cpu "\${GALAXY_SLOTS:-1}" --min_rad '$advanced.min_rad' --max_rad '$advanced.max_rad' --min_volume '$advanced.min_volume' #if $advanced.catalytic_residue: --catalytic_residue '$advanced.catalytic_residue' #end if #if $advanced.catalytic_site_coord: --catalytic_site_coord '$advanced.catalytic_site_coord' #end if #if $advanced.box_size: --box_size '$advanced.box_size' #end if
